func (o PbfPolicyImportState) MarshalJSON() ([]byte, error) {
	type shadow struct {
		Location interface{} `json:"location"`
		Names    []string    `json:"names"`
	}
	var location_object interface{}
	{
		var err error
		location_object, err = TypesObjectToMap(o.Location, PbfPolicyLocationSchema())
		if err != nil {
			return nil, fmt.Errorf("failed to marshal location into JSON document: %w", err)
		}
	}
	var names_list []string
	{
		diags := o.Names.ElementsAs(context.TODO(), &names_list, false)
		if diags.HasError() {
			return nil, NewDiagnosticsError("Failed to marshal names into JSON document", diags.Errors())
		}
	}

	obj := shadow{
		Location: location_object,
		Names:    names_list,
	}

	return json.Marshal(obj)
}

func (o *PbfPolicyImportState) UnmarshalJSON(data []byte) error {
	var shadow struct {
		Location interface{} `json:"location"`
		Names    []string    `json:"names"`
	}

	err := json.Unmarshal(data, &shadow)
	if err != nil {
		return err
	}
	var location_object types.Object
	{
		location_map, ok := shadow.Location.(map[string]interface{})
		if !ok {
			return NewDiagnosticsError("Failed to unmarshal JSON document into location: expected map[string]interface{}", nil)
		}
		var err error
		location_object, err = MapToTypesObject(location_map, PbfPolicyLocationSchema())
		if err != nil {
			return fmt.Errorf("failed to unmarshal location from JSON: %w", err)
		}
	}
	var names_list types.List
	{
		var diags_tmp diag.Diagnostics
		names_list, diags_tmp = types.ListValueFrom(context.TODO(), types.StringType, shadow.Names)
		if diags_tmp.HasError() {
			return NewDiagnosticsError("Failed to unmarshal JSON document into names", diags_tmp.Errors())
		}
	}
	o.Location = location_object
	o.Names = names_list

	return nil
}

func PbfPolicyImportStateCreator(ctx context.Context, resource types.Object) ([]byte, error) {
	attrs := resource.Attributes()
	if attrs == nil {
		return nil, fmt.Errorf("Object has no attributes")
	}

	locationAttr, ok := attrs["location"]
	if !ok {
		return nil, fmt.Errorf("location attribute missing")
	}

	var location types.Object
	switch value := locationAttr.(type) {
	case types.Object:
		location = value
	default:
		return nil, fmt.Errorf("location attribute expected to be an object")
	}
	itemsAttr, ok := attrs["rules"]
	if !ok {
		return nil, fmt.Errorf("rules attribute missing")
	}

	var items []*PbfPolicyResourceRulesObject
	switch value := itemsAttr.(type) {
	case types.List:
		diags := value.ElementsAs(ctx, &items, false)
		if diags.HasError() {
			return nil, fmt.Errorf("Invalid rules attribute element type, expected list of valid objects")
		}
	default:
		return nil, fmt.Errorf("Invalid names attribute type, expected list of strings")
	}

	var names []string
	for _, elt := range items {
		names = append(names, elt.Name.ValueString())
	}

	var namesObject types.List
	namesObject, diags_tmp := types.ListValueFrom(ctx, types.StringType, names)
	if diags_tmp.HasError() {
		return nil, NewDiagnosticsError("Failed to generate import ID", diags_tmp.Errors())
	}

	importStruct := PbfPolicyImportState{
		Location: location,
		Names:    namesObject,
	}

	return json.Marshal(importStruct)
}

func (o *PbfPolicyResource) ImportState(ctx context.Context, req resource.ImportStateRequest, resp *resource.ImportStateResponse) {

	var obj PbfPolicyImportState
	data, err := base64.StdEncoding.DecodeString(req.ID)
	if err != nil {
		resp.Diagnostics.AddError("Failed to decode Import ID", err.Error())
		return
	}

	var encryptedValues []byte
	ev, err := NewEncryptedValuesManager(encryptedValues, false)
	if err != nil {
		resp.Diagnostics.AddError("Failed to read encrypted values from private state", err.Error())
		return
	}

	err = json.Unmarshal(data, &obj)
	if err != nil {
		var diagsErr *DiagnosticsError
		if errors.As(err, &diagsErr) {
			resp.Diagnostics.Append(diagsErr.Diagnostics()...)
		} else {
			resp.Diagnostics.AddError("Failed to unmarshal Import ID", err.Error())
		}
		return
	}

	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("location"), obj.Location)...)
	if resp.Diagnostics.HasError() {
		return
	}

	var names []*PbfPolicyResourceRulesObject
	var objectNames []string
	resp.Diagnostics.Append(obj.Names.ElementsAs(ctx, &objectNames, false)...)
	if resp.Diagnostics.HasError() {
		return
	}
	for _, elt := range objectNames {
		object := &PbfPolicyResourceRulesObject{}
		resp.Diagnostics.Append(object.CopyFromPango(ctx, o.client, nil, &pbf.Entry{}, ev)...)
		if resp.Diagnostics.HasError() {
			return
		}
		object.Name = types.StringValue(elt)
		names = append(names, object)
	}
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("rules"), names)...)
}

